      "parameter": "swgr.ambient_temperature_range",
      "operator": "range",
      "value": [-5, 45],
      "unit": "deg C",
      "condition": null,
      "quote": "Switchgear shall be rated for continuous operation over an ambient temperature range of -5°C to 45°C."
    },
    {
      "parameter": "swgr.temperature_rise",
      "operator": "<=",
      "value": "limits per IEC 62271-200 Table 4",
      "unit": null,
      "condition": "at 45°C ambient",
      "quote": "Temperature rise of busbars and connections shall not exceed the limits specified in IEC 62271-200 Table 4 at 45°C ambient."
    }
  ]
}
